 33→    beams: [],
 34→    stairs: [],
 35→    landings: [],
 36→    fixtures: [],
 37→    annotations: [],
 38→    annotationSettings: createAnnotationSettings(),
 39→    slabs: [],
 40→    sectionCuts: [],
 41→  };
 42→}
