213→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
214→  const area = polygonArea(points);
215→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
216→  return {
217→    id: generateId('room'),
218→    name,
219→    points: points.map(p => ({ x: p.x, y: p.y })),
220→    labelPosition: { ...centroid },
221→    color,
222→    area,
223→  };
224→}
