  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { buildPreviewScene } from '@/three/scene/buildPreviewScene';
  4→import { buildPreviewObjectRoot } from './buildPreviewObjects';
  5→import { createPreviewViewport } from './createPreviewViewport';
  6→import { getOrderedFloors } from '@/domain/floorModels';
  7→import { getPreviewInspection } from './previewInspection';
  8→import { resolveWalkFloorContext } from './resolveWalkFloorContext';
  9→import { ExpandIcon, CollapseIcon } from '@/ui/ToolbarIcons';
 10→import styles from './ThreePreviewPanel.module.css';
 11→
 12→export default function ThreePreviewPanel({ project, activeFloorId, isMaximized = false, onToggleMaximize, className = '' }) {
 13→  const viewportRef = useRef(null);
 14→  const containerRef = useRef(null);
 15→  const resizeObserverRef = useRef(null);
 16→  const [previewScope, setPreviewScope] = useState('all');
 17→  const [navigationMode, setNavigationMode] = useState('inspect');
 18→  const [walkUiState, setWalkUiState] = useState({
 19→    navigationMode: 'inspect',
 20→    isLocked: false,
 21→    canLock: false,
 22→  });
 23→  const { selectedId, selectedType, dispatch: editorDispatch } = useEditor();
 24→
 25→  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
 26→
 27→  const visibleFloorIds = useMemo(() => {
 28→    if (previewScope === 'all') return undefined;
 29→    if (orderedFloors.some((f) => f.id === previewScope)) return [previewScope];
 30→    return undefined;
 31→  }, [previewScope, orderedFloors]);
 32→
 33→  const sceneDescriptor = useMemo(() => buildPreviewScene(project, {
 34→    activeFloorId,
 35→    visibleFloorIds,
 36→  }), [project, activeFloorId, visibleFloorIds]);
 37→
 38→  const activeFloor = (project?.floors || []).find((floor) => floor.id === activeFloorId) || null;
 39→  const visibleCount = sceneDescriptor.floors
 40→    .filter((floor) => floor.visible)
 41→    .reduce((count, floor) => count + floor.objects.length, 0);
 42→  const visibleFloorCount = sceneDescriptor.floors.filter((floor) => floor.visible).length;
 43→  const inspection = useMemo(
 44→    () => getPreviewInspection(project, selectedType, selectedId),
 45→    [project, selectedId, selectedType]
 46→  );
 47→  const walkFloorContext = useMemo(
 48→    () => resolveWalkFloorContext(sceneDescriptor, activeFloorId),
 49→    [sceneDescriptor, activeFloorId]
 50→  );
 51→  const visibleInspection = inspection && sceneDescriptor.visibleFloorIds.includes(inspection.floorId)
 52→    ? inspection
 53→    : null;
 54→  const handlePreviewScopeChange = useCallback((nextScope) => {
 55→    setPreviewScope(nextScope);
 56→
 57→    if (nextScope === 'all') return;
 58→    if (!orderedFloors.some((floor) => floor.id === nextScope)) return;
 59→    if (nextScope !== activeFloorId) {
 60→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId: nextScope });
 61→    }
 62→  }, [activeFloorId, editorDispatch, orderedFloors]);
 63→  const handlePreviewPick = useCallback((target) => {
 64→    if (!target?.sourceId || !target?.kind) {
 65→      editorDispatch({ type: 'DESELECT' });
 66→      return;
 67→    }
 68→
 69→    if (target.floorId && target.floorId !== activeFloorId) {
 70→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId: target.floorId });
 71→    }
 72→
 73→    editorDispatch({ type: 'SELECT_OBJECT', id: target.sourceId, objectType: target.kind });
 74→  }, [activeFloorId, editorDispatch]);
 75→
 76→  useEffect(() => {
 77→    if (!containerRef.current) return undefined;
 78→
 79→    const viewport = createPreviewViewport(containerRef.current);
 80→    viewportRef.current = viewport;
 81→
 82→    if ('ResizeObserver' in window) {
 83→      const observer = new ResizeObserver(() => {
 84→        viewport.resize();
 85→      });
 86→      observer.observe(containerRef.current);
 87→      resizeObserverRef.current = observer;
 88→    }
 89→
 90→    viewport.resize();
 91→
 92→    return () => {
 93→      resizeObserverRef.current?.disconnect?.();
 94→      resizeObserverRef.current = null;
 95→      viewport.dispose();
 96→      viewportRef.current = null;
 97→    };
 98→  }, []);
 99→
100→  useEffect(() => {
101→    viewportRef.current?.setPickHandler(handlePreviewPick);
102→  }, [handlePreviewPick]);
103→
104→  useEffect(() => {
105→    viewportRef.current?.setPickContext({ activeFloorId });
106→  }, [activeFloorId]);
107→
108→  useEffect(() => {
109→    viewportRef.current?.setWalkUiHandler(setWalkUiState);
110→    viewportRef.current?.setWalkExitHandler(() => {
111→      setNavigationMode('inspect');
112→    });
113→  }, []);
114→
115→  useEffect(() => {
116→    const viewport = viewportRef.current;
117→    if (!viewport) return;
118→
119→    const root = buildPreviewObjectRoot(sceneDescriptor, viewport.materialPalette, {
120→      selectedId,
121→      selectedType,
122→    });
123→    viewport.setWorld(root, sceneDescriptor.bounds, sceneDescriptor.groundLevel);
124→  }, [sceneDescriptor, selectedId, selectedType]);
125→
126→  useEffect(() => {
127→    viewportRef.current?.setNavigationMode(navigationMode);
128→  }, [navigationMode]);
129→
130→  useEffect(() => {
131→    viewportRef.current?.setActiveFloorContext(walkFloorContext);
132→  }, [walkFloorContext]);
133→
134→  const resetLabel = navigationMode === 'walk' ? 'Reset Walk' : 'Reset View';
135→  const primaryFooter = navigationMode === 'walk'
136→    ? (walkUiState.isLocked
137→      ? 'Look: mouse · Fly: W/A/S/D · Up/Down: R/F · Faster: Shift · Exit: Esc'
138→      : 'Walk: click preview to capture mouse · Fly: W/A/S/D · Up/Down: R/F · Faster: Shift · Exit: Esc')
139→    : 'Orbit: drag · Pan: right drag · Zoom: wheel · Inspect: click object';
140→  const secondaryFooter = navigationMode === 'walk'
141→    ? 'Ghost walk is noclip flight now, still read-only and collision-free.'
142→    : 'Perspective preview, future-ready for presets and floor visibility.';
143→
144→  return (
145→    <section className={`${styles.panel} ${className}`}>
146→      <div className={styles.header}>
147→        <div className={styles.titleGroup}>
148→          <span className={styles.eyebrow}>3D Preview</span>
149→          <span className={styles.title}>
150→            {activeFloor
151→              ? `${visibleFloorCount === 1 ? '1 floor' : `${visibleFloorCount} floors`} · ${visibleCount} objects`
152→              : 'No active floor'}
153→          </span>
154→        </div>
155→        <div className={styles.actions}>
156→          <div className={styles.modeToggle} role="group" aria-label="Preview navigation mode">
157→            <button
158→              type="button"
159→              className={navigationMode === 'inspect' ? styles.modeButtonActive : styles.modeButton}
160→              onClick={() => setNavigationMode('inspect')}
161→              aria-pressed={navigationMode === 'inspect'}
162→            >
163→              Inspect
164→            </button>
165→            <button
166→              type="button"
167→              className={navigationMode === 'walk' ? styles.modeButtonActive : styles.modeButton}
168→              onClick={() => setNavigationMode('walk')}
169→              aria-pressed={navigationMode === 'walk'}
170→            >
171→              Walk
172→            </button>
173→          </div>
174→          <select
175→            className={styles.floorSelect}
176→            value={previewScope}
177→            onChange={(e) => handlePreviewScopeChange(e.target.value)}
178→          >
179→            <option value="all">All Floors</option>
180→            {orderedFloors.map((floor) => (
181→              <option key={floor.id} value={floor.id}>{floor.name}</option>
182→            ))}
183→          </select>
184→          <button
185→            type="button"
186→            className={styles.button}
187→            onClick={() => viewportRef.current?.resetView()}
188→          >
189→            {resetLabel}
190→          </button>
191→          {onToggleMaximize && (
192→            <button
193→              type="button"
194→              className={`${styles.button} ${styles.iconButton}`}
195→              onClick={onToggleMaximize}
196→              title={isMaximized ? 'Restore split view' : 'Maximize preview'}
197→              aria-label={isMaximized ? 'Restore split view' : 'Maximize preview'}
198→            >
199→              {isMaximized ? <CollapseIcon /> : <ExpandIcon />}
200→            </button>
201→          )}
202→        </div>
203→      </div>
204→
205→      <div className={styles.viewportWrap}>
206→        <div ref={containerRef} className={styles.viewport} />
