  1→import { doorOutlineOnWall, positionOnWall, projectPointOnWall, wallAngle, wallLength, wallOutline, windowOutlineOnWall } from '@/geometry/wallGeometry';
  2→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
  3→
  4→const EPSILON = 1e-6;
  5→
  6→function clamp(value, min, max) {
  7→  return Math.max(min, Math.min(max, value));
  8→}
  9→
 10→function buildOpeningDescriptor(kind, source, context) {
 11→  const outlineInfo = kind === 'door'
 12→    ? doorOutlineOnWall(context.sourceWall, source)
 13→    : windowOutlineOnWall(context.sourceWall, source);
 14→
 15→  const sourceCenterAlong = projectPointOnWall(context.sourceWall, outlineInfo.center);
 16→  const sourceStartAlong = sourceCenterAlong - source.width / 2;
 17→  const sourceEndAlong = sourceCenterAlong + source.width / 2;
 18→  const clippedSourceStartAlong = clamp(sourceStartAlong, context.trimStartAlong, context.trimEndAlong);
 19→  const clippedSourceEndAlong = clamp(sourceEndAlong, context.trimStartAlong, context.trimEndAlong);
 20→  const visibleWidth = clippedSourceEndAlong - clippedSourceStartAlong;
 21→
 22→  const baseElevation = context.wallBase + (source.sillHeight ?? 0);
 23→  const topElevation = baseElevation + (source.height ?? 0);
 24→  const visibleBaseElevation = clamp(baseElevation, context.wallBase, context.wallTop);
 25→  const visibleTopElevation = clamp(topElevation, context.wallBase, context.wallTop);
 26→  const visibleHeight = visibleTopElevation - visibleBaseElevation;
 27→
 28→  if (visibleWidth <= EPSILON || visibleHeight <= EPSILON) {
 29→    return null;
 30→  }
 31→
 32→  const startAlong = clippedSourceStartAlong - context.trimStartAlong;
 33→  const endAlong = clippedSourceEndAlong - context.trimStartAlong;
 34→  const centerAlong = (startAlong + endAlong) / 2;
 35→  const startPoint = positionOnWall(context.renderWall, startAlong);
 36→  const endPoint = positionOnWall(context.renderWall, endAlong);
 37→  const centerPoint = positionOnWall(context.renderWall, centerAlong);
 38→
 39→  return {
 40→    id: source.id,
 41→    kind,
 42→    type: source.type || (kind === 'window' ? 'standard' : 'swing'),
 43→    openDirection: source.openDirection || 'left',
 44→    wallId: context.wall.id,
 45→    sourceId: source.id,
 46→    angle: wallAngle(context.renderWall),
 47→    wallThickness: context.renderWall.thickness,
 48→    width: source.width,
 49→    height: source.height ?? 0,
 50→    sillHeight: source.sillHeight ?? 0,
 51→    startAlong,
 52→    endAlong,
 53→    centerAlong,
 54→    visibleWidth,
